// ══════════════════════════════════════════════════
// GESTOR DE SESIÓN — Lee sesión desde hoja USUARIOS
// ══════════════════════════════════════════════════
const usuario = $input.first().json;
const trigger = $('HelpDeskBot Trigger').first().json;
const inputText = (trigger.message?.text || '').trim();
const username  = String(trigger.message?.chat?.id || '');
const nombre    = trigger.message?.from?.first_name || 'Usuario';

const sesionActual = (usuario.sesion || '').trim();
const sesionDataStr = usuario.sesion_data || '{}';
let sesionData = {};
try { sesionData = JSON.parse(sesionDataStr); } catch(e) {}

// /start o sin sesión → menú principal
if (!sesionActual || inputText === '/start') {
  return [{ json: { pantalla: 'MENU_PRINCIPAL', sesionData: {}, username, nombre, inputText } }];
}

// Navegación especial desde MIS_SOLICITUDES
if (sesionActual === 'MIS_SOLICITUDES') {
  if (inputText === '0' || inputText === '9') {
    return [{ json: { pantalla: 'MENU_PRINCIPAL', sesionData: {}, username, nombre, inputText } }];
  }
  // Número 1-5 → ver detalle del ticket
  return [{ json: { pantalla: 'VER_DETALLE_TICKET', sesionData, username, nombre, inputText } }];
}

return [{ json: { pantalla: sesionActual, sesionData, username, nombre, inputText } }];

// ══════════════════════════════════════════════════
// ROUTER PRINCIPAL
// Convierte pantalla+input en la siguiente acción
// ══════════════════════════════════════════════════
const { pantalla, sesionData, username, nombre, inputText } = $input.first().json;

// Desde MENU_PRINCIPAL: enrutar por número
if (pantalla === 'MENU_PRINCIPAL') {
  const opciones = {
    '0': 'MENU_PRINCIPAL',
    '1': 'CREAR_SOLICITUD',
    '2': 'ESTADO_SOLICITUD',
    '3': 'MIS_SOLICITUDES',
    '4': 'REPORTES',
    '5': 'CONFIGURACION',
    '6': 'AYUDA',
    '7': 'REPORTE POR TIPO DE SOLICITUD'
  };
  const destino = opciones[inputText] || 'MENU_PRINCIPAL';
  return [{ json: { currentScreen: destino, sesionData, username, nombre, inputText } }];
}

// Desde CONFIGURACION: enrutar opciones del panel
if (pantalla === 'CONFIGURACION') {
  const opciones = {
    '1': 'ESPERANDO_TELEFONO',
    '2': 'VER_DATOS',
    '9': 'MENU_PRINCIPAL'
  };
  const destino = opciones[inputText];
  if (destino) {
    return [{ json: { currentScreen: destino, sesionData, username, nombre, inputText } }];
  }
  // Opción inválida en configuracion → mostrar panel de nuevo
  return [{ json: { currentScreen: 'CONFIGURACION', sesionData, username, nombre, inputText } }];
}

// En wizard o submenú: pasar tal cual para que el switch lo maneje
return [{ json: { currentScreen: pantalla, sesionData, username, nombre, inputText } }];

const { sesionData, username, nombre, inputText } = $input.first().json;
const tipoMap = {'1':'Soporte técnico','2':'Solicitud administrativa','3':'Consulta general'};
if (inputText === '9') {
  return [{ json: { accion: 'CANCELAR', sesionData, username, nombre, inputText } }];
}
if (!tipoMap[inputText]) {
  return [{ json: { accion: 'TIPO_INVALIDO', sesionData, username, nombre, inputText } }];
}
const nuevaData = { ...sesionData, tipo: tipoMap[inputText] };
return [{ json: { accion: 'TIPO_OK', sesionData: nuevaData, username, nombre, inputText } }];

const { sesionData, username, nombre, inputText } = $input.first().json;
const prioMap = {'1':'Alta','2':'Media','3':'Baja'};
if (inputText === '9') {
  return [{ json: { accion: 'CANCELAR', sesionData, username, nombre, inputText } }];
}
if (!prioMap[inputText]) {
  return [{ json: { accion: 'PRIO_INVALIDA', sesionData, username, nombre, inputText } }];
}
const nuevaData = { ...sesionData, prioridad: prioMap[inputText] };
return [{ json: { accion: 'PRIO_OK', sesionData: nuevaData, username, nombre, inputText } }];

const { sesionData, username, nombre, inputText } = $input.first().json;
if (inputText === '9' || inputText.toLowerCase() === 'cancelar') {
  return [{ json: { accion: 'CANCELAR', sesionData, username, nombre, inputText } }];
}
if (inputText.length < 10) {
  return [{ json: { accion: 'DESC_CORTA', sesionData, username, nombre, inputText } }];
}
const ticketId = 'TIC-' + Math.floor(Date.now()/1000);
const fecha = new Date().toLocaleString('es-CO',{timeZone:'America/Bogota'});
const nuevaData = { ...sesionData, descripcion: inputText, ticketId, fecha };
return [{ json: { accion: 'DESC_OK', sesionData: nuevaData, username, nombre, inputText } }];

const { sesionData, username, nombre, inputText } = $input.first().json;
if (inputText === '1') {
  return [{ json: { accion: 'CONFIRMAR_OK', sesionData, username, nombre, inputText } }];
}
return [{ json: { accion: 'CANCELAR', sesionData, username, nombre, inputText } }];

