const solicitudes = $input.all().map(i => i.json).filter(s => s.id_ticket);
const activas = solicitudes.filter(s => {
  const e = (s.estado||'').toLowerCase();
  return e === 'abierto' || e === 'abierta' || e === 'en proceso';
}).reverse().slice(0,5);
if (activas.length === 0) {
  return [{ json: { lista_tickets: '✅ No tienes solicitudes pendientes en este momento.' } }];
}
let msg = '';
activas.forEach(t => {
  const emoji = (t.estado||'').toLowerCase()==='en proceso' ? '🟡' : '🟢';
  msg += emoji + ' *ID:* `' + t.id_ticket + '`\n';
  msg += 'Estado: _' + t.estado + '_\n\n';
});
return [{ json: { lista_tickets: msg } }];

