const tickets = $input.all().map(i => i.json).filter(t => t.id_ticket);
const activos = tickets.filter(t => {
  const e = (t.estado||'').toLowerCase();
  return e !== 'cerrado' && e !== 'cerrada';
}).reverse().slice(0,5);
if (activos.length === 0) {
  return [{ json: { mensaje_lista: '📭 No tienes solicitudes activas.\n\nCrea una desde el menú principal.', tiene_tickets: false } }];
}
const lista = activos.map((t,i) => (i+1)+'. `'+t.id_ticket+'` — _'+t.tipo+'_ — '+t.estado).join('\n');
return [{ json: { mensaje_lista: lista, tiene_tickets: true } }];

