const s = $input.all().map(i => i.json).filter(t => t.id_ticket);
let abiertas = 0, proceso = 0, cerradas = 0;
let tecnico = 0, admin = 0, consulta = 0;

s.forEach(t => {
  const e = (t.estado || '').toLowerCase().trim();
  if (e === 'abierto' || e === 'abierta') abiertas++;
  else if (e === 'en proceso') proceso++;
  else if (e === 'cerrado' || e === 'cerrada') cerradas++;

  const tipo = (t.tipo || '').toLowerCase();
  if (tipo.includes('técnico') || tipo.includes('tecnico')) tecnico++;
  else if (tipo.includes('administrativa') || tipo.includes('admin')) admin++;
  else if (tipo.includes('consulta') || tipo.includes('general')) consulta++;
});

const total = s.length;

if (total === 0) {
  return [{ json: { reporte: '📊 *Reporte de Solicitudes*\n\nNo hay solicitudes registradas aún.\n\nEscribe *0* para volver al menú.' } }];
}

const fecha = new Date().toLocaleDateString('es-CO', { timeZone: 'America/Bogota' });

return [{ json: { reporte:
  '📊 *Reporte General — HelpDeskBot*\n' +
  '_Generado: ' + fecha + '_\n\n' +
  '*Por estado:*\n' +
  '🟢 Abiertas: ' + abiertas + '\n' +
  '🟡 En proceso: ' + proceso + '\n' +
  '🔵 Cerradas: ' + cerradas + '\n' +
  '─────────────────\n' +
  '📈 *Total: ' + total + '*\n\n' +
  '*Por tipo:*\n' +
  '⚙️ Soporte técnico: ' + tecnico + '\n' +
  '📊 Solicitud administrativa: ' + admin + '\n' +
  '🤔 Consulta general: ' + consulta
}}];

const s = $input.all().map(i => i.json).filter(t => t.id_ticket);

let abiertas = 0, proceso = 0, cerradas = 0;

let tecnico = { total: 0, abiertas: 0, proceso: 0, cerradas: 0 };
let admin = { total: 0, abiertas: 0, proceso: 0, cerradas: 0 };
let consulta = { total: 0, abiertas: 0, proceso: 0, cerradas: 0 };

s.forEach(t => {
  const e = (t.estado || '').toLowerCase().trim();
  const tipo = (t.tipo || '').toLowerCase();

  let estadoKey = '';
  if (e === 'abierto' || e === 'abierta') {
    abiertas++;
    estadoKey = 'abiertas';
  } else if (e === 'en proceso') {
    proceso++;
    estadoKey = 'proceso';
  } else if (e === 'cerrado' || e === 'cerrada') {
    cerradas++;
    estadoKey = 'cerradas';
  }

  if (tipo.includes('técnico') || tipo.includes('tecnico')) {
    tecnico.total++;
    if (estadoKey) tecnico[estadoKey]++;
  } else if (tipo.includes('administrativa') || tipo.includes('admin')) {
    admin.total++;
    if (estadoKey) admin[estadoKey]++;
  } else if (tipo.includes('consulta') || tipo.includes('general')) {
    consulta.total++;
    if (estadoKey) consulta[estadoKey]++;
  }
});

const total = s.length;

let tipoFrecuente = 'Soporte técnico';
if (admin.total > tecnico.total && admin.total > consulta.total) {
  tipoFrecuente = 'Administrativa';
} else if (consulta.total > tecnico.total && consulta.total > admin.total) {
  tipoFrecuente = 'Consulta general';
}


return [{ json: { reporte2:
      'Reporte de solicitudes\n\n' +
      'Resumen general\n' +
      '- Tipo más frecuente: ' + tipoFrecuente + '\n' +
      '- Total solicitudes: ' + total + '\n' +
      '- Interacciones con el bot: 25\n\n' +
      'Detalle por tipo\n' +
      '1) Soporte técnico\n' +
      '   - Total: ' + tecnico.total + '\n' +
      '   - Abiertas: ' + tecnico.abiertas + '\n' +
      '   - En proceso: ' + tecnico.proceso + '\n' +
      '   - Cerradas: ' + tecnico.cerradas + '\n\n' +
      '2) Administrativa\n' +
      '   - Total: ' + admin.total + '\n' +
      '   - Abiertas: ' + admin.abiertas + '\n' +
      '   - En proceso: ' + admin.proceso + '\n' +
      '   - Cerradas: ' + admin.cerradas  + '\n\n' +
      '3) Consulta general\n' +
      '   - Total: ' + consulta.total + '\n' +
      '   - Abiertas: ' + consulta.abiertas + '\n' +
      '   - En proceso: ' + consulta.proceso + '\n' +
      '   - Cerradas: ' + consulta.cerradas
  }
}];
